elapsed = context['elapsed']
cycle_idx = int(elapsed // 180)
ck = f'spd_{cycle_idx}'
if ck not in cache:
    rng = random.Random(cycle_idx * 7 + 1)
    cache[ck] = {'dur': rng.randint(-8, 10), 'spd': rng.uniform(-40, 40)}
off = cache[ck]
period = 180 + off['dur']; t = elapsed % period
ramp = 8; cut_end = period - 25 - ramp
if t < 20:
    target = 0
elif t < 20 + ramp:
    target = (2000 + off['spd']) * ((t - 20) / ramp)
elif t < cut_end:
    target = 2000 + off['spd']
elif t < cut_end + ramp:
    target = (2000 + off['spd']) * (1 - (t - cut_end) / ramp)
else:
    target = 0
noise = random.gauss(0, 12) if target > 100 else 0
result = int(round(max(0, min(8000, target + noise))))

elapsed = context['elapsed']
cycle_idx = int(elapsed // 180)
ck = f'feed_{cycle_idx}'
if ck not in cache:
    rng = random.Random(cycle_idx * 7 + 2)
    cache[ck] = {'dur': rng.randint(-8, 10), 'feed': rng.uniform(-30, 50)}
off = cache[ck]
period = 180 + off['dur']; t = elapsed % period
cut_end = period - 25 - 8
if t < 30:
    target = 0
elif t < 40:
    target = 400 + 400 * ((t - 30) / 10.0)
elif t < cut_end:
    base_feed = 800 + off['feed']
    corner = 80 * math.sin(2 * math.pi * elapsed / 23.7) * max(0, math.sin(2 * math.pi * elapsed / 41.3))
    target = base_feed + corner
elif t < cut_end + 12:
    target = 350
else:
    target = 0
noise = random.gauss(0, 18) if target > 0 else 0
result = round(max(0, min(5000, target + noise)), 1)

elapsed = context['elapsed']
cycle_idx = int(elapsed // 180)
ck = f'cur_{cycle_idx}'
if ck not in cache:
    rng = random.Random(cycle_idx * 7 + 3)
    cache[ck] = {'dur': rng.randint(-8, 10), 'cur': rng.uniform(-1.5, 2.0)}
off = cache[ck]
period = 180 + off['dur']; t = elapsed % period
cut_end = period - 25 - 8
if t < 20:
    base, noise_std = 2.2, 0.2
elif t < 20 + 8:
    base, noise_std = 6.0, 0.7
elif t < 40:
    base, noise_std = 23.5 + off['cur'], 1.8
elif t < cut_end:
    drift = 0.8 * math.sin(2 * math.pi * elapsed / 37.4) + 0.5 * math.sin(2 * math.pi * elapsed / 19.1)
    base, noise_std = 21.5 + off['cur'] + drift, 1.0
elif t < cut_end + 12:
    base, noise_std = 6.0, 0.7
elif t < cut_end + 20:
    base, noise_std = 3.5, 0.4
else:
    base, noise_std = 2.2, 0.2
result = round(max(0, min(40.0, base + random.gauss(0, noise_std))), 2)

elapsed = context['elapsed']
cycle_idx = int(elapsed // 180)
ck = f'load_{cycle_idx}'
if ck not in cache:
    rng = random.Random(cycle_idx * 7 + 7)
    cache[ck] = {'dur': rng.randint(-8, 10), 'load': rng.uniform(-4.0, 6.0)}
off = cache[ck]
period = 180 + off['dur']; t = elapsed % period
cut_end = period - 25 - 8
if t < 20:
    base, noise_std = 0.0, 0.0
elif t < 20 + 8:
    base, noise_std = 6.0, 1.5
elif t < 40:
    base, noise_std = 68.0 + off['load'], 3.5
elif t < cut_end:
    drift = 4.5 * math.sin(2 * math.pi * elapsed / 37.4) + 2.5 * math.sin(2 * math.pi * elapsed / 19.1) + 1.5 * math.sin(2 * math.pi * elapsed / 7.3)
    base, noise_std = 56.0 + off['load'] + drift, 2.5
elif t < cut_end + 12:
    base, noise_std = 6.0, 1.5
elif t < cut_end + 20:
    base, noise_std = 2.0, 0.8
else:
    base, noise_std = 0.0, 0.0
noise = random.gauss(0, noise_std) if noise_std > 0 else 0
result = round(max(0, min(120.0, base + noise)), 2)
